// howl.config.ts — applies to every endpoint
defineConfig<State, Role>({
  roles,
  defaultRateLimit: { max: 100, windowMs: 60_000 },
});

// a route — override
rateLimit: { max: 10, windowMs: 60_000 }

// a route — disable
rateLimit: false

rateLimit: {
  max: 5,
  windowMs: 60_000,        // 5 attempts per minute
  blockDurationMs: 3_600_000, // then locked out for 1 hour
}

import { memoryCache, redisCache } from "@hushkey/howl/api/cache";

defineConfig<State, Role>({
  roles,
  cache: memoryCache(),         // response cache — per-instance is fine
  rateLimitCache: redisCache(r), // counters — must be shared
});
